const input = $input.first().json;
const body = input.body ?? input;
const question = typeof body.question === 'string' && body.question.trim() ? body.question.trim() : 'What should I know from the current wiki state?';
const limit = Number.isFinite(Number(body.limit)) && Number(body.limit) > 0 ? Number(body.limit) : 8;
return [{ json: { question, limit } }];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('search.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const payload = {
  question: $node["Prepare Query"].json.question,
  retrieval: $input.first().json
};
return [{
  json: {
    payload,
    payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('answer-context.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const packet = $input.first().json;
const answerRecordPayload = {
  answer_record: packet.answer_record,
  answer: '<replace with provider LLM answer text>'
};
return [{
  json: {
    status: 'needs_provider_llm_node',
    question: packet.question,
    context_docs: packet.context_docs,
    retrieval: packet.retrieval,
    answer_record: packet.answer_record,
    llm_instructions: [
      'Insert your provider-specific LLM node after Parse Answer Context.',
      'Use context_docs[*].body as grounded markdown context.',
      'Generate the answer first; do not update wiki directly here.',
      'Then call answer-record.ts with { answer_record, answer }.',
      'Finally produce a canonical Feedback Record and send it to KB - Apply Feedback.'
    ],
    answer_record_command: 'npm --silent --prefix /app run answer-record -- --vault /data/vault',
    answer_record_payload_shape: answerRecordPayload,
    next_workflow: 'KB - Apply Feedback'
  }
}];
